// 根据中水规范对各级标题及正文进行排版
var doc = Application.ActiveDocument;
var paragraphs = doc.Paragraphs;

// 定义中水规范常用样式
var styles = {
    '一级标题': 'Heading 1',
    '二级标题': 'Heading 2', 
    '三级标题': 'Heading 3',
    '正文': 'Normal'
};

for (var i = 1; i <= paragraphs.Count; i++) {
    var para = paragraphs.Item(i);
    var text = para.Range.Text.replace(/[\r\n]/g, '').trim();

    if (!text) continue;

    // 识别一级标题：第一章、第二章... 或 第X章
    if (/^第[一二三四五六七八九十百]+章\s/.test(text)) {
        para.Style = doc.Styles.Item('Heading 1');
        para.Range.Font.Name = '黑体';
        para.Range.Font.Size = 16; // 三号
        para.Range.Font.Bold = true;
        para.Alignment = 1; // 居中
        para.OutlineLevel = 1;
    }
    // 识别二级标题：1.1、1.2...
    else if (/^\d+\.\d+\s/.test(text)) {
        para.Style = doc.Styles.Item('Heading 2');
        para.Range.Font.Name = '黑体';
        para.Range.Font.Size = 14; // 四号
        para.Range.Font.Bold = true;
        para.OutlineLevel = 2;
    }
    // 识别三级标题：1.1.1、1.1.2...
    else if (/^\d+\.\d+\.\d+\s/.test(text)) {
        para.Style = doc.Styles.Item('Heading 3');
        para.Range.Font.Name = '黑体';
        para.Range.Font.Size = 12; // 小四
        para.Range.Font.Bold = true;
        para.OutlineLevel = 3;
    }
    // 表格标题：表 X.X-X
    else if (/^表\s+\d+\.\d+-\d+\s+/.test(text)) {
        para.Range.Font.Name = '宋体';
        para.Range.Font.Size = 12; // 小四
        para.Range.Font.Bold = false;
        para.Alignment = 1; // 居中
    }
    // 正文内容
    else {
        para.Style = doc.Styles.Item('Normal');
        para.Range.Font.Name = '宋体';
        para.Range.Font.Size = 12; // 小四
        para.Format.LineSpacing = 18; // 1.5倍行距（约18磅）
        para.OutlineLevel = 99; // 正文
    }
}

return '已完成排版：共处理' + paragraphs.Count + '个段落';
